8	import Foundation
9	
10	/// Калибровка каналов спектра по энергии излучения
11	struct EnergyCalibrationCommand: BluetoothCommand {
12	    
13	    enum Action {
14	        case read
15	        case write(Write)
16	        
17	        enum Write {
18	            case reset
19	            case new(CalibrationCoefficients)
20	        }
21	    }
22	    
23	    let request: BluetoothCommandRequest
24	    
25	    init(action: Action) {
26	        let type: BluetoothCommandType
27	        let payload: [UInt8]?
28	        
29	        switch action {
30	        case .read:
31	            type = .readVirtualString
32	            payload = nil
33	        case .write(let write):
34	            type = .writeVirtualString
35	            switch write {
36	            case .reset:
37	                payload = nil
38	            case .new(let coefficients):
39	                payload = [coefficients.a0, coefficients.a1, coefficients.a2].flatMap { $0.asBytes }
40	            }
41	        }
42	        self.request = .init(
43	            type: type,
44	            command: .energyCalibration,
45	            payload: payload
46	        )
47	    }
48	}
49	
50	// MARK: - Response
51	
52	extension EnergyCalibrationCommand {
53	    
54	    struct Response {
55	        let coefficients: [Float]
56	    }
57	    
58	    var response: BluetoothCommandResponseBuilder<Response> {
59	        .init { data in
60	            guard data.isValid, !data.body.isEmpty else { return .init(coefficients: []) }
61	            let bytes = data.body
62	            return .init(coefficients: [
63	                bytes.toFloat(start: 0),
64	                bytes.toFloat(start: 4),
65	                bytes.toFloat(start: 8)
66	            ])
67	        }
68	    }
69	}
