8	import Foundation
9	import Combine
10	import FactoryKit
11	
12	extension Container {
13	    var spectrumDataRepository: Factory<SpectrumDataRepository> {
14	        self { SpectrumDataRepositoryImpl() }
15	            .singleton
16	    }
17	}
18	
19	/// Репозиторий работы со спектром
20	protocol SpectrumDataRepository: SpectrumSettingsSetup {
21	    
22	    /// Издатель подключенного спектра
23	    var spectrumSubject: PassthroughSubject<SpectrumData, Never> { get }
24	    
25	    /// Запускает получение спектра
26	    func startSpectrumCollect()
27	    
28	    /// Останавливает получение спектра
29	    func cancelSpectrumCollect()
30	}
31	
32	final class SpectrumDataRepositoryImpl: SpectrumDataRepository {
33	    
34	    @Injected(\.deviceManager) private var deviceManager
35	    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
36	
37	    var specFormatVersion = false
38	    var spectrumDisabled = false
39	
40	    private var delay: Double = 0.8
41	    private var spectrumCollectTask: Task<Void, Error>?
42	    
43	    var spectrumSubject: PassthroughSubject<SpectrumData, Never> = .init()
44	    
45	    private var cancellable: Set<AnyCancellable> = .init()
46	
47	    init() {
48	        deviceConnectionManager.connectionSubject
49	            .filter(\.isReady)
50	            .sink { [weak self] _ in
51	                guard let self else { return }
52	                self.startSpectrumCollect()
53	            }
54	            .store(in: &cancellable)
55	    }
56	    
57	    func startSpectrumCollect() {
58	        guard !spectrumDisabled else { return }
59	        guard spectrumCollectTask == nil else { return }
60	        spectrumCollectTask = Task {
61	            repeat {
62	                try await sendSpectrumCommand()
63	            } while !Task.isCancelled
64	        }
65	    }
66	    
67	    func cancelSpectrumCollect() {
68	        spectrumCollectTask?.cancel()
69	        spectrumCollectTask = nil
70	    }
71	    
72	    private func sendSpectrumCommand() async throws {
73	        let result = await deviceManager.send(command: SpectrumCommand(specFormatVersion: specFormatVersion))
74	        if case .success(let response) = result {
75	            let spectrum = SpectrumData(
76	                time: response.time,
77	                coefficients: response.coefficients,
78	                countNeg: response.countNeg,
79	                pulses: response.pulses
80	            )
81	            spectrumSubject.send(spectrum)
82	        }
83	        try await Task.sleep(seconds: delay)
84	    }
85	}
