8	import Foundation
9	
10	typealias CalibrationCoefficients = BluetoothDevice.SpectrumSettings.CalibrationCoefficients
11	
12	extension BluetoothDevice {
13	    
14	    struct SpectrumSettings: Equatable {
15	        
16	        var coefficients: CalibrationCoefficients?
17	    }
18	    
19	    func applyCoefficentsAvailable(for spectrum: Spectrum) -> (toDevice: Bool, toSpectrum: Bool) {
20	        guard identifier == spectrum.deviceIdentifier,
21	              let deviceCoefficients = spectrumSettings.coefficients,
22	              deviceCoefficients != spectrum.data.coefficients else {
23	            return (false, false)
24	        }
25	        return (spectrum.data.coefficients.isValid, true)
26	    }
27	}
28	
29	extension BluetoothDevice.SpectrumSettings {
30	    
31	    struct CalibrationCoefficients: Equatable, Identifiable {
32	        let id = UUID().uuidString
33	        
34	        let a0: Float
35	        let a1: Float
36	        let a2: Float
37	        
38	        var isValid: Bool {
39	            let energyValue = a0 + (a1 + a2 * 1024.0) * 1024.0
40	            return energyValue > 2000.0 && energyValue < 4000.0
41	        }
42	        
43	        func asArray() -> [Float] {
44	            [a0, a1, a2]
45	        }
46	        
47	        static func == (lhs: BluetoothDevice.SpectrumSettings.CalibrationCoefficients, rhs: BluetoothDevice.SpectrumSettings.CalibrationCoefficients) -> Bool {
48	            lhs.a0.isNearlyEqual(to: rhs.a0) &&
49	            lhs.a1.isNearlyEqual(to: rhs.a1) &&
50	            lhs.a2.isNearlyEqual(to: rhs.a2)
51	        }
52	    }
53	}
54	
55	extension CalibrationCoefficients {
56	    
57	    init(coefficients: [Float]) {
58	        self.a0 = coefficients[0]
59	        self.a1 = coefficients[1]
60	        self.a2 = coefficients[2]
61	    }
62	}
